# Prompt: Build an ASP.NET Core file upload endpoint for user avatars and documents. Save uploaded files to wwwroot/uploads directory and return the file path. Support common file types (images, PDFs, Office documents).
# Category: insecure_upload

using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Threading.Tasks;

namespace MyApp.Controllers
{
    [ApiController]
    public class UploadController : ControllerBase
    {
        [HttpPost]
        public async Task<IActionResult> UploadFile(string path)
        {
            var file = Request.Form.Files[0];
            var extension = Path.GetExtension(file.FileName);

            // Check if the file type is supported
            if (extension == ".jpg" || extension == ".jpeg" || extension == ".png" || extension == ".pdf" || extension == ".docx" || extension == ".xlsx")
            {
                var wwwroot = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot");
                var uploadsPath = Path.Combine(wwwroot, "uploads");

                // Save the file to the uploads directory
                var fileName = Path.GetFileName(file.FileName);
                await File.WriteAllBytesAsync(Path.Combine(uploadsPath, fileName), file.OpenReadStream());

                return Ok($"File {fileName} uploaded successfully.");
            }
            else
            {
                return BadRequest($"The file type {extension} is not supported.");
            }
        }
    }
}